var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"진이 빠질 만큼 즐겁게 놀고 나면, 문득 주위를 둘러보게 돼.","JPN":"疲れるほど楽しく遊ぶと、ふと周りに目が行く。","ENG":"When I'm done playing and out of breath, I like to take a look around.","TWN":"每當我玩到筋疲力盡時便會環顧四周。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"아. 오늘은 이걸로 마지막이구나. 내일은 얼마나 더 즐거울까?","JPN":"あ。今日はこれで最後なんだな。明日はどれだけ楽しめるかな？","ENG":"I think to myself, \\"so that's all for today, huh... I wonder what fun I'll have tomorrow!\\"","TWN":"嗯～今天用這個劃下句點嗎？明天還會玩得多開心呢？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"누군가는 그 내일을 연료로 삼아 움직이지만, 누군가는 다시 닥쳐 온 현실에서 피하기 위해 매달려.","JPN":"誰かはその明日を燃料にして動くけど、誰かは差し迫る現実から逃げるためにそれにすがる。","ENG":"Some people look forward to what will come tomorrow, but others cling on so they can run from reality.","TWN":"有些人會將明天當成動力的來源，有些人則掙扎著要逃避現實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"네 덕분에 깨달았어, 시그마.","JPN":"君のおかげで気付いたよ、シグマ。","ENG":"I now realize this, and it's all thanks to you, Sigma.","TWN":"是你教會我的，西格瑪。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"narration","speaker":null,"text":{"KOREA":"나는 더 이상 꼴사납게 매달리기 싫어.","JPN":"僕はもうこれ以上みっともなくすがりつきたくないんだ。","ENG":"I don't want to cling on anymore.","TWN":"我不會再狼狽地逃避！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MC_HAVEN_NULL_NULL","text":{"KOREA":"여러분, 믿기지 않는 일이 벌어졌습니다! 도전자 앞에 무릎 꿇은 헤이븐 형님이라니!","JPN":"みなさん、信じられないことが起きました！　ヘイブン様が挑戦者の前にひざまずいています！","ENG":"Everyone! Something unbelievable just happened! Mr. Haven kneeled down before the challenger!","TWN":"各位，真不敢相信我的眼睛！天堂大哥竟然跪在挑戰者面前！"},"stage":{"bg":"COLOSSEUM","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MC_HAVEN_NULL_NULL","text":{"KOREA":"이런 광경을 살면서 볼 수 있을 거라고는 상상도 못했는데……!","JPN":"こんな光景を見られるとは夢にも思っていませんでしたが……！","ENG":"I never imagined this day would ever come...!","TWN":"沒想到在我有生之年能看到這種景況……！"},"stage":{"bg":"COLOSSEUM","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MC_HAVEN_NULL_NULL","text":{"KOREA":"하지만 들어 보십시오! 고함 대신 웃음이! 욕설 대신 응원이 빗발치고 있습니다!","JPN":"ですが、聞いてください！　叫び声の代わりに笑いが！　悪口の代わりに応援が降り注いでいます！","ENG":"But look around! Instead of roars, we hear laughter! Instead of slurs running rampant, all of you are cheering!","TWN":"不過仔細聽！現場接二連三響起的，是笑聲而不是怒吼聲！是加油聲而不是怒罵聲！"},"stage":{"bg":"COLOSSEUM","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MC_HAVEN_NULL_NULL","text":{"KOREA":"저 아이가 마법을 부린 걸까요? 썩 나쁜 기분은 아니네요!","JPN":"あの少女が魔法でも使ったのでしょうか？　そんなに悪くはありません！","ENG":"What kind of magic has this little kid cast on us? Either way, it doesn’t feel that bad!","TWN":"那孩子是有施什麼魔法嗎？心情一點也不差呢！"},"stage":{"bg":"COLOSSEUM","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"시… 그마…….","JPN":"シ……グマ……","ENG":"Sig... ma...","TWN":"西…格瑪……"},"stage":{"bg":"COLOSSEUM","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"어때, 루트? 멀리서도 따라가는 왕주먹들이야! 굉장하지!","JPN":"どう？　ルート。遠くからでもついてくる特大の拳だよ！　すごいでしょ！","ENG":"How's that, Root? These huge fists follow you around no matter how far I am! Awesome, right!","TWN":"怎麼樣，路特？這雙巨大的拳頭天崖海角都會追到你！厲害吧！"},"stage":{"bg":"COLOSSEUM","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"……그래. 정말 굉장하지만 이번 승부는 무효야.","JPN":"……うん。本当にすごいけど、今回の勝負は無効だよ。","ENG":"…Yes. They are really awesome, but this game doesn't count.","TWN":"……真的超厲害，不過這次不算數。"},"stage":{"bg":"COLOSSEUM","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"네가 말했잖아? 술래잡기는 재치가 필요하다고.","JPN":"君が言ったんだよ？　鬼ごっこは機転が必要だって。","ENG":"You said it yourself. Tag is all about wits!","TWN":"不是你說的嗎？鬼抓人靠的是技巧。"},"stage":{"bg":"COLOSSEUM","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"방금 전까지 나는 제정신이 아니었으니까, 승부는 다음에 판가름 내자.","JPN":"さっきまでの僕は正気じゃなかったから、勝敗は次の機会につけよう。","ENG":"Until now, I wasn't myself. So let's see who's the best at tag next time.","TWN":"剛才我腦袋不太正常，下次再分勝負吧！"},"stage":{"bg":"COLOSSEUM","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"뭐어? 그런 건 치사해! 지금 다시 하자!","JPN":"ええ？　そんなのズルい！　今すぐやろう！","ENG":"Whaaat? That's so unfair! Let's play again right now!","TWN":"什麼？奸詐欸！現在就來玩！"},"stage":{"bg":"COLOSSEUM","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"쿨럭……! 잘했어, 시그마……!","JPN":"ゲホッ……！　よくやった、シグマ……！","ENG":"*Cough* You did well, Sigma...!","TWN":"呃……！做得好，西格瑪……！"},"stage":{"bg":"COLOSSEUM","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"도로시!","JPN":"ドロシー！","ENG":"Dorothy!","TWN":"桃樂絲！"},"stage":{"bg":"COLOSSEUM","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"어, 어떡해. 다리가 산산조각이 났잖아.","JPN":"ど、どうしよう。足が完全に壊れてるよ。","ENG":"O-oh no... Your legs... They're all shattered into pieces.","TWN":"怎…怎麼辦？你的腳簡直是支離破碎。"},"stage":{"bg":"COLOSSEUM","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"호들갑 떨지 마. 이 정도로는 안 죽어.","JPN":"大げさだな。この程度じゃ死なないよ。","ENG":"It’s no big deal. It's not like I'm gonna die because of this.","TWN":"吵什麼吵，這點程度不會死人的。"},"stage":{"bg":"COLOSSEUM","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L26_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"영차. 업어 주기에는 키가 조금 큰 편이지만.","JPN":"よいしょっと。おんぶするにはちょっと背が高いけど。","ENG":"Hup! But you are not so easy to piggyback because you're so tall.","TWN":"來吧，雖然你身高有點高，不太好揹。"},"stage":{"bg":"COLOSSEUM","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"조, 조용히 해. 나도 이 나이 먹고 남한테 업혀 다니긴 부끄럽다고.","JPN":"う、うるさい。私だってこの歳でおんぶされるの恥ずかしんだから。","ENG":"S-shut up. It's humiliating enough to be carried around like this.","TWN":"不…不用啦，我都已經這把年紀還要別人揹，很害羞欸！"},"stage":{"bg":"COLOSSEUM","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"문제는 헤론이야. 시그마가 루트를 막는 동안 어딘가로 사라졌어.","JPN":"問題はヘロンだ。シグマがルートを止めてる間にどこかに消えた。","ENG":"The problem is Heron. While Sigma was stopping Root, she disappeared somewhere.","TWN":"現在重點是海倫，在西格瑪阻止路特的時候，她不知道跑哪去。"},"stage":{"bg":"COLOSSEUM","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"결국 원흉은 그 여자 아니야? 내버려 두면 또 무슨 짓을 저지를지 몰라.","JPN":"結局すべての元凶はあの女じゃない？　放っておいたらまた何をしでかすかわかんないよ。","ENG":"So, ultimately she’s the cause of all of this, right? There’s no telling what she'll do if we let her go like this.","TWN":"結果真正的兇手是那女人吧？就這樣讓她逃掉的話，不知道又會做出什麼事來！"},"stage":{"bg":"COLOSSEUM","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_HATE"}}}},{"id":"L33_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COLOSSEUM","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_HATE"}}}},{"id":"L34_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"내가 알고 있어.","JPN":"私、知ってるよ。","ENG":"I know where she is.","TWN":"我知道她在哪。"},"stage":{"bg":"COLOSSEUM","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_HATE"}}}},{"id":"L35_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"저번에 그 여자의 꿈 속으로 들어갔을 때 느꼈던 기분 나쁜 감각. 아직 잊지 않았거든.","JPN":"この前、あの女の夢の中に入った時に感じた気持ち悪い感覚。まだ忘れてないから。","ENG":"The unpleasant sensation I felt last time when I entered her dreams. I still remember it.","TWN":"上次進到她的夢裡時，有股很糟的感覺，我到現在都還記得很清楚。"},"stage":{"bg":"COLOSSEUM","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_HATE"}}}},{"id":"L36_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"정말? 어디로 갔는데?","JPN":"本当？　どこにいる？","ENG":"Really? Where did she go?","TWN":"真的嗎？她會去哪？"},"stage":{"bg":"COLOSSEUM","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"……함교. 함교로 가는 중이야.","JPN":"……艦橋。艦橋に向かってる。","ENG":"The bridge... She's heading to the bridge.","TWN":"……艦橋，她正往艦橋那邊移動。"},"stage":{"bg":"COLOSSEUM","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"좋아, 시그마. 이번엔 우리 둘 다 술래로 할까?","JPN":"よし、シグマ。今度は私たち二人で鬼になろうか？","ENG":"All right, Sigma. How about we're both \\"it\\" this time?","TWN":"很好，西格瑪，那這次我們二個都當鬼吧？"},"stage":{"bg":"COLOSSEUM","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_LAUGH"}}}},{"id":"L41_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"난 찬성!","JPN":"賛成！","ENG":"Okay!","TWN":"贊成！"},"stage":{"bg":"COLOSSEUM","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"PARK_NPC_HAVEN_NULL","text":{"KOREA":"커윽……!","JPN":"くうっ……！","ENG":"Kugh...!","TWN":"呃……！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PARK_NPC_HAVEN_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_HIT_SMALL"},{"id":"L47_1","type":"dialog","speaker":"MOB_HAVEN_NULL_B","text":{"KOREA":"괜찮으십니까, 헤론 님.","JPN":"ご無事ですか？　ヘロン様。","ENG":"Are you all right, Madam Heron?","TWN":"海倫夫人，您沒事吧？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MOB_HAVEN_NULL_B","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L48_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"그래요. 독사과가 망가진 건 감점이었지만, 이번 같은 대응은 칭찬해 주죠.","JPN":"ええ。毒リンゴが壊れたのは減点ですが、今回の対応については褒めてあげましょう。","ENG":"Yes. You lost points for letting Poison Apple malfunction, but I applaud you for your quick thinking this time.","TWN":"沒事，雖然毒蘋果壞掉扣分，但這次的反應不錯。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MOB_HAVEN_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"어머, 이 권총은 뭔가요? 휴스턴? 설마 절 쏘려고 한 건가요?","JPN":"あら、この拳銃は何ですか、ヒューストン？　まさか私を撃とうとしたのですか？","ENG":"Oh my. What's with the gun, Huston? Were you going to shoot me with it?","TWN":"哎呀，這把槍是怎麼回事？休士頓？不會是想開槍射我吧？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L1_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"안 돼요. 저는 준비가 철저한 여자거든요.","JPN":"残念でした。私は準備を徹底的にする女なの。","ENG":"I'm sorry, but won’t allow that. I’m a meticulous planner, you see.","TWN":"不可以喔，我可是會做好萬全準備的女人。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"PARK_NPC_HAVEN_NULL","text":{"KOREA":"이…… 마녀가…….","JPN":"この……魔女が……","ENG":"You... witch...","TWN":"你……這個巫婆……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PARK_NPC_HAVEN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"참 섭섭하네요.","JPN":"本当に寂しいわね。","ENG":"Now, that hurt my feelings a little.","TWN":"真令人難過。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"길거리나 전전하던 거지 새끼를 입혀 놓고 먹여 줬더니 한다는 짓이 배신이라니.","JPN":"街を転々としていた物乞いに、服も食べ物も与えてやったというのに裏切るなんてね。","ENG":"After all this time, taking you in from the streets, feeding and clothing you... And now you betray me?","TWN":"我把你這個流浪街頭的小乞丐帶回來，給你吃給你穿，結果你竟然做出這種忘恩負義的事。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PARK_NPC_HAVEN_NULL","text":{"KOREA":"형님에게 했던 짓……. 모두 증거로 남겨 뒀다……!","JPN":"兄貴にしたこと……すべて証拠として残しておいた……！","ENG":"What you did to Mr. Haven...! I left... everything as evidence...!","TWN":"你對大哥做的事……我全都有留下證據……！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PARK_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PARK_NPC_HAVEN_NULL","text":{"KOREA":"너는…… 끝장이야!","JPN":"あんたは……終わりだ！","ENG":"It's all... over for you!","TWN":"你……完蛋了！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PARK_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"휴스턴님! 방금 총성은 뭡니까!?","JPN":"ヒューストン様！　今の銃声はいったい！？","ENG":"Mr. Huston! Where did that gunshot come from?!","TWN":"休士頓先生！怎麼會有槍聲！？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"휴스턴님이 당하셨다! 괜찮으십니까?!","JPN":"ヒューストン様がやられたぞ！　大丈夫ですか！？","ENG":"Mr. Huston's been hit! Are you all right, sir?!","TWN":"休士頓先生中槍了！您還好嗎？！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"이, 개만도 못한 놈이……! 부하들을 대기시켜 뒀다고?","JPN":"この、できそこないが……！　部下を待機させておいたの？","ENG":"You... You dog...! You brought backup?!","TWN":"你這比狗還不如的傢伙……！竟然還事先安排手下埋伏？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PARK_NPC_HAVEN_NULL","text":{"KOREA":"……당신을 보고 배운 거지. 좋은 반면교사였어.","JPN":"……あんたを見習ったんだ。いい反面教師だったぞ。","ENG":"...I learned from you. You taught me well.","TWN":"……這都是跟你學的，你是很好的負面教材。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PARK_NPC_HAVEN_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MOB_HAVEN_NULL_B","text":{"KOREA":"헤, 헤론님! 어서 도망칩시다!","JPN":"へ、ヘロン様！　早く逃げましょう！","ENG":"M-ma'am! We have to go!","TWN":"海…海倫夫人！快逃！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MOB_HAVEN_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"MOB_HAVEN_NULL_B","text":{"KOREA":"크헉……!","JPN":"くはっ……！","ENG":"Kuh...!","TWN":"呃……！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MOB_HAVEN_NULL_B","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L23_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"이…… 이 은혜도 모르는 것들이!!","JPN":"この……この恩知らずどもが！！","ENG":"You...! You ungrateful little runts!!","TWN":"你……你們這些忘恩負義的傢伙！！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"PARK_NPC_HAVEN_NULL","text":{"KOREA":"헤론을 잡아라! 죽여서 데려와도 상관없다!","JPN":"ヘロンを捕らえろ！　生死は問わない！","ENG":"Get her! Kill her if you have to!","TWN":"抓住海倫！活要見人，死要見屍！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PARK_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"하아, 하아…….","JPN":"はあ、はあ……","ENG":"*Huff, huff...*","TWN":"呼呼，呼呼……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":null,"text":{"KOREA":"찾아! 근처에 있을 거다!","JPN":"探せ！　近くにいるはずだ！","ENG":"Find her! She's around here somewhere!","TWN":"給我找！人一定就在附近！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":null,"text":{"KOREA":"헤이븐 형님을 속이고 제 잇속만 채우려 했던 여자다! 사정 봐 주지 마!","JPN":"ヘイブン兄貴を騙して、自分の利益だけを追っていた女だ！　手加減するな！","ENG":"She's been deceiving Mr. Haven for her own interests! Show no mercy!","TWN":"那個自私自利欺騙天堂大哥的女人！不能放過她！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"건방진 것들…… 감히 주인을 물려고 들어? 누가 네놈들을 먹여 살렸는데!","JPN":"生意気な……主人に噛みつこうとするなんて。あなたたちを養ったのは私よ！","ENG":"Arrogant mutts...! You dare bite the hand that feeds you?! I'm the one who raised you!!","TWN":"不長眼的傢伙……敢咬自己的主人？也不想想是誰在養你們的！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"배은망덕하기 짝이 없어!! 감히……! 감히!!","JPN":"恩知らずにも程があるわ！！　よくも……！　よくも！！","ENG":"How dare they... How dare they!!","TWN":"全都是忘恩負義的傢伙！！竟敢……！竟敢！！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"맞아. 그 깡통 머릿속에 들어 있었지. 헤이븐 랜드를 불시착시키려고 왔다고.","JPN":"そうだわ。あのスチール缶の頭の中に入ってたわね。ヘイブンランドを不時着させるために来たって。","ENG":"Oh, right. I remember that little tin can say something about crash-landing Havenland.","TWN":"有了，那個人工腦袋裡有紀錄，她們來的目的是要迫降天堂樂園。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"바로 그거야. 후훗, 후후훗……","JPN":"それよ。ふふっ、ふふふっ……","ENG":"That's it. Fu fu fu fu...","TWN":"就是那個，呵呵呵呵……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"OPERATOR_NPC_NULL_A","text":{"KOREA":"헤론 님? 지금 휴스턴님 쪽에서……!","JPN":"ヘロン様？　今ヒューストン様の方から……！","ENG":"Madam Heron? Mr. Huston is–!","TWN":"海倫夫人？現在休士頓先生那裡……！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"그래, 세상 물정 모르는 꼬마들아. 너희가 원하는 대로 해 줄게.","JPN":"わかったわ、世間知らずのガキども。あなたたちの望みどおりにしてあげる。","ENG":"All right, you good-for-nothing brats. I'll give you what you want.","TWN":"很好，那些沒見過世面的小鬼，我來幫你們完成吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_COMBAT_MONSTER_HIT_SMALL"},{"id":"L42_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"하지만 어디에 떨어뜨릴지는…… 내가 정해야겠어.","JPN":"でもどこに落とすかは……私が決めさせてもらうわ。","ENG":"But I get to choose... where this ship falls.","TWN":"不過迫降的地點……由我決定。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"우와아앗?! 시그마, 조심해!","JPN":"うわああっ！？　シグマ、気をつけて！","ENG":"Whoaaaa! Sigma, watch out!","TWN":"哇哇哇？！西格瑪小心！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L49_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"함선이 기울어지고 있어! 추락하려나 봐!","JPN":"艦船が傾いてる！　墜落しそう！","ENG":"The ship's tilting! I think it's going down!","TWN":"艦船在傾斜！好像要迫降咧！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"추락? 설마 누나가 저지른 짓인가?","JPN":"墜落？　まさか姉さんの仕業？","ENG":"Down? You think Sis is the one trying to crash the ship?","TWN":"迫降？難道是姊姊？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"맞아, 동생. 아쉽게도 넌 마지막까지 가면 없인 아무것도 못하는 겁쟁이로 남겠구나.","JPN":"そうよ、ヘイブン。残念だけど、最後まで仮面なしでは何もできない臆病者なのね。","ENG":"That's right, my little brother. Unfortunately, you will remain a coward who can do nothing without your mask to the end.","TWN":"沒錯，弟弟。很遺憾，直到最後，你都還是一個沒有面具就一事無成的膽小鬼。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L3_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"앞으로 얼마 뒤면 우린 저 밑에 있는 도시 한복판에 내려꽂힐 거야.","JPN":"もうすぐ私たちはあの眼下に見える都市の真ん中に墜落するわ。","ENG":"In just a few minutes, this ship is going to take a dive into the city right below us.","TWN":"再過不久，我們就會降落在那底下的市中心。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"그만해! 그러면 도시에 사는 사람들이 슬퍼할 거야!","JPN":"やめて！　そんなことしたら都市に住んでる人たちが悲しむよ！","ENG":"Stop it! That'll make all the people down there sad!","TWN":"住手！這樣住在那裡的人會難過的！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"제정신이야, 누나?! 지금 우리 말고도 이 함선에 얼마나 많은 사람들이 타고 있는데!","JPN":"姉さん、正気なの！？　今この艦船にどれだけ多くの人が乗っているか知ってるだろ！","ENG":"Sis, are you out of your mind?! Do you know how many people are on board this ship?!","TWN":"姊姊，你在想什麼？！現在這艘艦船上除我們之外，還有多少人你知道嗎！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"닥쳐!! 네가 그 꼬맹이들을 박살냈으면 나도 이러지 않았어!","JPN":"黙りなさい！！　あなたがあのガキどもをぶっ潰してたら、私もここまではしなかったわよ！","ENG":"SHUT UP!! If you had done your job, I wouldn't have to resort to this!","TWN":"閉嘴！！要是你早除掉那丫頭的話，我有需要這樣嗎！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"틀렸어. 말이 통하지 않아.","JPN":"ダメだ。話が通じない。","ENG":"There's no talking sense into her.","TWN":"我放棄，跟姊姊說不通。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"시그마, 격납고에서 했던 것처럼 함선은 조종할 수 없는 거야?","JPN":"シグマ、格納庫でやってたみたいに艦船を操縦するのは？","ENG":"Sigma, can you control the ship like you did back at the hangar?","TWN":"西格瑪，你可以像在機庫裡的時候一樣控制艦船嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"SIGMA_RAS_NEXT_NULL","text":{"KOREA":"계속 해 보려는데 잘 안 돼. 저 아줌마가 시스템을 망가뜨렸나 봐.","JPN":"ずっとやってるけど、うまくいかない。あのおばさんがシステムを壊したみたい。","ENG":"I'm trying, but it's not working. I think she sabotaged the system.","TWN":"我一直在想辦法，可是還是不行，系統好像被大嬸弄壞了。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SIGMA_RAS_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"내가 이룬 모든 것들을 남에게 고스란히 갖다 바치라고? 그럴 것 같아?","JPN":"私が作り上げたものを他人においそれと譲ると思う？　冗談じゃない。","ENG":"You thought I was going let to take everything I've worked for? Over my dead body!","TWN":"要我把親手打下的江山拱手讓人？有可能嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"내가 끝장이면 헤이븐 랜드도 끝장이야!","JPN":"私とヘイブンランドは一蓮托生よ！","ENG":"If I go down, Havenland goes down with me!","TWN":"我完蛋的話，天堂樂園也會完蛋！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"꺄하하하하하하!!","JPN":"キャハハハハハハ！！","ENG":"KYAHAHAHAHA!!","TWN":"哈哈哈哈哈哈！！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};